            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V19, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V13, NDS_VEC_V19, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V14, NDS_VEC_V19, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
            vl_pending = vl_next_a;
            pending_alt = 1;

            if (colCnt < (unsigned long)maxvl_per_loop) break;

            /* === Phase B: pending in V24-V31 -> load next into V16-V23, compute V24-V31 === */
            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VLB_V(NDS_VEC_V16, pA);
            NDS_VEC_VLB_V(NDS_VEC_V17, pA2);
            NDS_VEC_VLB_V(NDS_VEC_V18, pA3);
            NDS_VEC_VLB_V(NDS_VEC_V19, pA4);
            NDS_VEC_VLB_V(NDS_VEC_V20, pB);
            NDS_VEC_VLB_V(NDS_VEC_V21, pB2);
            NDS_VEC_VLB_V(NDS_VEC_V22, pB3);
            NDS_VEC_VLB_V(NDS_VEC_V23, pB4);
            pA += vl;  pA2 += vl;  pA3 += vl;  pA4 += vl;
            pB += vl;  pB2 += vl;  pB3 += vl;  pB4 += vl;
            colCnt -= vl;
            long vl_next_b = vl;
            NDS_VEC_VSETVLI(vl, vl_pending, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0,  NDS_VEC_V24, NDS_VEC_V28);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V1,  NDS_VEC_V24, NDS_VEC_V29);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V2,  NDS_VEC_V24, NDS_VEC_V30);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V3,  NDS_VEC_V24, NDS_VEC_V31);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V4,  NDS_VEC_V25, NDS_VEC_V28);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V5,  NDS_VEC_V25, NDS_VEC_V29);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V6,  NDS_VEC_V25, NDS_VEC_V30);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V7,  NDS_VEC_V25, NDS_VEC_V31);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V8,  NDS_VEC_V26, NDS_VEC_V28);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V9,  NDS_VEC_V26, NDS_VEC_V29);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V10, NDS_VEC_V26, NDS_VEC_V30);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V11, NDS_VEC_V26, NDS_VEC_V31);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V27, NDS_VEC_V28);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V13, NDS_VEC_V27, NDS_VEC_V29);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V14, NDS_VEC_V27, NDS_VEC_V30);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V15, NDS_VEC_V27, NDS_VEC_V31);
            vl_pending = vl_next_b;
            pending_alt = 0;
        }

        // Drain: compute the last-loaded batch (no overlapping load).
        NDS_VEC_VSETVLI(vl, vl_pending, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        if (pending_alt)
        {
            // pending in V24-V31
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0,  NDS_VEC_V24, NDS_VEC_V28);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V1,  NDS_VEC_V24, NDS_VEC_V29);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V2,  NDS_VEC_V24, NDS_VEC_V30);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V3,  NDS_VEC_V24, NDS_VEC_V31);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V4,  NDS_VEC_V25, NDS_VEC_V28);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V5,  NDS_VEC_V25, NDS_VEC_V29);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V6,  NDS_VEC_V25, NDS_VEC_V30);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V7,  NDS_VEC_V25, NDS_VEC_V31);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V8,  NDS_VEC_V26, NDS_VEC_V28);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V9,  NDS_VEC_V26, NDS_VEC_V29);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V10, NDS_VEC_V26, NDS_VEC_V30);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V11, NDS_VEC_V26, NDS_VEC_V31);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V27, NDS_VEC_V28);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V13, NDS_VEC_V27, NDS_VEC_V29);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V14, NDS_VEC_V27, NDS_VEC_V30);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V15, NDS_VEC_V27, NDS_VEC_V31);
        }
        else
        {
            // pending in V16-V23
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0,  NDS_VEC_V16, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V1,  NDS_VEC_V16, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V2,  NDS_VEC_V16, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V3,  NDS_VEC_V16, NDS_VEC_V23);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V4,  NDS_VEC_V17, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V5,  NDS_VEC_V17, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V6,  NDS_VEC_V17, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V7,  NDS_VEC_V17, NDS_VEC_V23);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V8,  NDS_VEC_V18, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V9,  NDS_VEC_V18, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V11, NDS_VEC_V18, NDS_VEC_V23);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V19, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V13, NDS_VEC_V19, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V14, NDS_VEC_V19, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
        }

        // Tail: colCnt > 0 means remaining elements not a multiple of maxvl_per_loop.
        // Zero pixel buffers to avoid junk in partial vd4dotsu groups.
        if (colCnt > 0)
        {
            long tmp_avl = colCnt + 3;
            NDS_VEC_VSETVLI(vl, tmp_avl, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VAND_VI(NDS_VEC_V20, NDS_VEC_V20, 0);
            NDS_VEC_VAND_VI(NDS_VEC_V21, NDS_VEC_V21, 0);
            NDS_VEC_VAND_VI(NDS_VEC_V22, NDS_VEC_V22, 0);
            NDS_VEC_VAND_VI(NDS_VEC_V23, NDS_VEC_V23, 0);
            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VLB_V(NDS_VEC_V20, pB);
            NDS_VEC_VLB_V(NDS_VEC_V21, pB2);
            NDS_VEC_VLB_V(NDS_VEC_V22, pB3);
            NDS_VEC_VLB_V(NDS_VEC_V23, pB4);
            NDS_VEC_VLB_V(NDS_VEC_V16, pA);
            NDS_VEC_VLB_V(NDS_VEC_V17, pA2);
            NDS_VEC_VLB_V(NDS_VEC_V18, pA3);
            NDS_VEC_VLB_V(NDS_VEC_V19, pA4);
            pA += vl;  pA2 += vl;  pA3 += vl;  pA4 += vl;
            vl = (vl + 3) >> 2;
            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0,  NDS_VEC_V16, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V1,  NDS_VEC_V16, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V2,  NDS_VEC_V16, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V3,  NDS_VEC_V16, NDS_VEC_V23);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V4,  NDS_VEC_V17, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V5,  NDS_VEC_V17, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V6,  NDS_VEC_V17, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V7,  NDS_VEC_V17, NDS_VEC_V23);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V8,  NDS_VEC_V18, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V9,  NDS_VEC_V18, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V11, NDS_VEC_V18, NDS_VEC_V23);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V19, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V13, NDS_VEC_V19, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V14, NDS_VEC_V19, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
        }
    }
    else
    {
        // Small K (< maxvl_per_loop): zero accumulators V0-V15 conventionally.
        NDS_VEC_VSETVLI(vl, col_src1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
        NDS_VEC_VAND_VI(NDS_VEC_V0,  NDS_VEC_V0,  0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V1,  NDS_VEC_V1,  0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V2,  NDS_VEC_V2,  0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V3,  NDS_VEC_V3,  0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V4,  NDS_VEC_V4,  0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V5,  NDS_VEC_V5,  0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V6,  NDS_VEC_V6,  0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V7,  NDS_VEC_V7,  0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V8,  NDS_VEC_V8,  0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V9,  NDS_VEC_V9,  0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V10, NDS_VEC_V10, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V11, NDS_VEC_V11, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V12, NDS_VEC_V12, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V13, NDS_VEC_V13, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V14, NDS_VEC_V14, 0x0);
        NDS_VEC_VAND_VI(NDS_VEC_V15, NDS_VEC_V15, 0x0);

        while (colCnt > 0)
        {
            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VLB_V(NDS_VEC_V16, pA);
            NDS_VEC_VLB_V(NDS_VEC_V17, pA2);
            NDS_VEC_VLB_V(NDS_VEC_V18, pA3);
            NDS_VEC_VLB_V(NDS_VEC_V19, pA4);
            NDS_VEC_VLB_V(NDS_VEC_V20, pB);
            NDS_VEC_VLB_V(NDS_VEC_V21, pB2);
            NDS_VEC_VLB_V(NDS_VEC_V22, pB3);
            NDS_VEC_VLB_V(NDS_VEC_V23, pB4);
            colCnt -= vl;
            pA += vl;  pA2 += vl;  pA3 += vl;  pA4 += vl;
            pB += vl;  pB2 += vl;  pB3 += vl;  pB4 += vl;
            vl >>= 2;
            NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0,  NDS_VEC_V16, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V1,  NDS_VEC_V16, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V2,  NDS_VEC_V16, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V3,  NDS_VEC_V16, NDS_VEC_V23);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V4,  NDS_VEC_V17, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V5,  NDS_VEC_V17, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V6,  NDS_VEC_V17, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V7,  NDS_VEC_V17, NDS_VEC_V23);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V8,  NDS_VEC_V18, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V9,  NDS_VEC_V18, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V10, NDS_VEC_V18, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V11, NDS_VEC_V18, NDS_VEC_V23);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V12, NDS_VEC_V19, NDS_VEC_V20);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V13, NDS_VEC_V19, NDS_VEC_V21);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V14, NDS_VEC_V19, NDS_VEC_V22);
            NDS_VEC_VD4DOTSU_VV(NDS_VEC_V15, NDS_VEC_V19, NDS_VEC_V23);
        }
    }
    pA = pA4;

    // === Reduction epilogue: 16 vredsum -> pack to VL=4 -> requantize ===
    // SW-pipeline Phase A loads pB4 into V31 each iteration; re-zero V31 here.
    NDS_VEC_VSETVLI(vl, col_src1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);

    // Reduce 16 accumulators to scalars in element [0].
    // pix0: ch0->V16[0], ch1->V17[0], ch2->V18[0], ch3->V19[0]
    NDS_VEC_VREDSUM_VS(NDS_VEC_V16, NDS_VEC_V0,  NDS_VEC_V31);  //ch0*pix0
    NDS_VEC_VREDSUM_VS(NDS_VEC_V17, NDS_VEC_V4,  NDS_VEC_V31);  //ch1*pix0
    NDS_VEC_VREDSUM_VS(NDS_VEC_V18, NDS_VEC_V8,  NDS_VEC_V31);  //ch2*pix0
    NDS_VEC_VREDSUM_VS(NDS_VEC_V19, NDS_VEC_V12, NDS_VEC_V31);  //ch3*pix0
    // pix1: ch0->V20[0], ch1->V21[0], ch2->V22[0], ch3->V23[0]
    NDS_VEC_VREDSUM_VS(NDS_VEC_V20, NDS_VEC_V1,  NDS_VEC_V31);  //ch0*pix1
    NDS_VEC_VREDSUM_VS(NDS_VEC_V21, NDS_VEC_V5,  NDS_VEC_V31);  //ch1*pix1
    NDS_VEC_VREDSUM_VS(NDS_VEC_V22, NDS_VEC_V9,  NDS_VEC_V31);  //ch2*pix1
    NDS_VEC_VREDSUM_VS(NDS_VEC_V23, NDS_VEC_V13, NDS_VEC_V31);  //ch3*pix1
    // pix2: ch0->V24[0], ch1->V25[0], ch2->V26[0], ch3->V27[0]
    NDS_VEC_VREDSUM_VS(NDS_VEC_V24, NDS_VEC_V2,  NDS_VEC_V31);  //ch0*pix2
    NDS_VEC_VREDSUM_VS(NDS_VEC_V25, NDS_VEC_V6,  NDS_VEC_V31);  //ch1*pix2
    NDS_VEC_VREDSUM_VS(NDS_VEC_V26, NDS_VEC_V10, NDS_VEC_V31);  //ch2*pix2
    NDS_VEC_VREDSUM_VS(NDS_VEC_V27, NDS_VEC_V14, NDS_VEC_V31);  //ch3*pix2
    // pix3: ch0->V28[0], ch1->V29[0], ch2->V30[0], ch3->V0[0] (reuse V0)
    NDS_VEC_VREDSUM_VS(NDS_VEC_V28, NDS_VEC_V3,  NDS_VEC_V31);  //ch0*pix3
    NDS_VEC_VREDSUM_VS(NDS_VEC_V29, NDS_VEC_V7,  NDS_VEC_V31);  //ch1*pix3
    NDS_VEC_VREDSUM_VS(NDS_VEC_V30, NDS_VEC_V11, NDS_VEC_V31);  //ch2*pix3
    NDS_VEC_VREDSUM_VS(NDS_VEC_V0,  NDS_VEC_V15, NDS_VEC_V31);  //ch3*pix3

    // Pack 4 scalars into VL=4 vectors via vslideup.
    // V16=pix0=[ch0,ch1,ch2,ch3], V20=pix1, V24=pix2, V28=pix3
    NDS_VEC_VSETVLI_E32(vl, 4);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V17, 1);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V18, 2);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V16, NDS_VEC_V19, 3);

    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V21, 1);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V22, 2);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V20, NDS_VEC_V23, 3);

    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V25, 1);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V26, 2);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V24, NDS_VEC_V27, 3);

    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V29, 1);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V30, 2);
    NDS_VEC_VSLIDEUP_VI(NDS_VEC_V28, NDS_VEC_V0,  3);  //V0 holds ch3*pix3

    //load bias (V1 is free here; V0 just slid up into V28)
    NDS_VEC_VLW_V(NDS_VEC_V1, bias);
    bias += vl;

    //add bias to acc
    NDS_VEC_VADD_VV(NDS_VEC_V16, NDS_VEC_V16, NDS_VEC_V1);
    NDS_VEC_VADD_VV(NDS_VEC_V20, NDS_VEC_V20, NDS_VEC_V1);
    NDS_VEC_VADD_VV(NDS_VEC_V24, NDS_VEC_V24, NDS_VEC_V1);
    NDS_VEC_VADD_VV(NDS_VEC_V28, NDS_VEC_V28, NDS_VEC_V1);

    //1st shift of 2-stage shift
    NDS_VEC_VSRA_VX(NDS_VEC_V16, NDS_VEC_V16, pre_rshift);
    NDS_VEC_VSRA_VX(NDS_VEC_V20, NDS_VEC_V20, pre_rshift);
    NDS_VEC_VSRA_VX(NDS_VEC_V24, NDS_VEC_V24, pre_rshift);
    NDS_VEC_VSRA_VX(NDS_VEC_V28, NDS_VEC_V28, pre_rshift);

    NDS_VEC_VMUL_VX(NDS_VEC_V16, NDS_VEC_V16, out_scale);
